/**
 * Test Generator
 *
 * Converts a DesignBlueprint + selected dimensions into a standalone Playwright
 * .spec.ts test file. This is the bridge between the constraint engine and the
 * Builder LLM — the generated test IS the spec the builder must satisfy.
 *
 * The generated file is completely self-contained: no imports from the DCE,
 * no dependencies beyond @playwright/test. This is intentional — the Builder
 * LLM receives ONLY the test file and must produce HTML/CSS that passes it.
 *
 * Flow:
 *   Blueprint -> applyConstraints(dimensions) -> assertions -> .spec.ts code
 */

import fs from 'fs/promises'
import path from 'path'
import type { DesignBlueprint, DimensionName } from '../types/blueprint.js'
import { applyConstraintsRecursive } from '../constraints/index.js'

/**
 * Generate a Playwright test file from a Blueprint.
 *
 * @param blueprint - The design blueprint to generate tests from
 * @param dimensions - Which dimensions to include in the test
 * @param outputPath - Where to write the .spec.ts file
 * @returns The generated test code as a string
 */
export async function generateTestFile(
  blueprint: DesignBlueprint,
  dimensions: readonly DimensionName[],
  outputPath: string,
): Promise<string> {
  const results = applyConstraintsRecursive(blueprint.components, dimensions)

  // Build the test file
  const lines: string[] = []

  // Header
  lines.push(`import { test, expect } from '@playwright/test';`)
  lines.push('')
  lines.push(`/**`)
  lines.push(` * Auto-generated design constraint tests for: ${blueprint.name}`)
  lines.push(` * Blueprint ID: ${blueprint.id}`)
  lines.push(` * Dimensions tested: ${dimensions.join(', ')}`)
  lines.push(` * Total components: ${results.length}`)
  lines.push(` * Total assertions: ${results.reduce((sum, r) => sum + r.assertions.length, 0)}`)
  lines.push(` *`)
  lines.push(` * Generated by Design Constraint Engine`)
  lines.push(` * Source: ${blueprint.source.imagePath}`)
  lines.push(` * Viewport: ${blueprint.source.viewport.width}x${blueprint.source.viewport.height}`)
  lines.push(` */`)
  lines.push('')

  // Test suite
  lines.push(`test.describe('${blueprint.name} Design Constraints', () => {`)
  lines.push(`  test.beforeEach(async ({ page }) => {`)
  lines.push(`    await page.setViewportSize({ width: ${blueprint.source.viewport.width}, height: ${blueprint.source.viewport.height} });`)
  lines.push(`    // Navigate to the built page — Builder LLM should serve at this URL`)
  lines.push(`    await page.goto('/');`)
  lines.push(`  });`)
  lines.push('')

  // Generate a test block for each component
  for (const { selector, name, assertions } of results) {
    // Create a sanitized variable name from the component name
    const varName = name.replace(/[^a-zA-Z0-9]/g, '_').replace(/^_+|_+$/g, '')

    lines.push(`  test('${name} constraints', async ({ page }) => {`)
    lines.push(`    const ${varName} = page.locator('${selector}');`)
    lines.push(`    await expect(${varName}).toBeVisible();`)
    lines.push('')

    // Group assertions by dimension for readability
    const byDimension = new Map<string, typeof assertions>()
    for (const a of assertions) {
      if (!byDimension.has(a.dimension)) byDimension.set(a.dimension, [])
      byDimension.get(a.dimension)!.push(a)
    }

    for (const [dim, dimAssertions] of byDimension) {
      lines.push(`    // --- ${dim} ---`)
      for (const assertion of dimAssertions) {
        lines.push(`    // ${assertion.description}`)
        lines.push(assertion.codegen(varName))
        lines.push('')
      }
    }

    lines.push(`  });`)
    lines.push('')
  }

  lines.push(`});`)
  lines.push('')

  const code = lines.join('\n')

  // Write to file
  await fs.mkdir(path.dirname(outputPath), { recursive: true })
  await fs.writeFile(outputPath, code)
  console.log(`  Generated ${outputPath}`)
  console.log(`    Components: ${results.length}, Assertions: ${results.reduce((sum, r) => sum + r.assertions.length, 0)}`)

  return code
}

/**
 * Generate a human-readable summary of the test constraints.
 * Useful as supplementary context for the Builder LLM.
 */
export function generateConstraintSummary(
  blueprint: DesignBlueprint,
  dimensions: readonly DimensionName[],
): string {
  const results = applyConstraintsRecursive(blueprint.components, dimensions)
  const lines: string[] = []

  lines.push(`# Design Constraints: ${blueprint.name}`)
  lines.push('')
  lines.push(`Viewport: ${blueprint.source.viewport.width}x${blueprint.source.viewport.height}`)
  lines.push(`Dimensions: ${dimensions.join(', ')}`)
  lines.push('')

  // Design tokens summary
  lines.push(`## Design Tokens`)
  const tokens = blueprint.tokens
  if (tokens.colors) {
    lines.push(`### Colors`)
    for (const [name, value] of Object.entries(tokens.colors)) {
      if (value) lines.push(`- ${name}: ${value}`)
    }
  }
  if (tokens.typography?.fontFamily) {
    lines.push(`### Typography`)
    lines.push(`- Font: ${tokens.typography.fontFamily}`)
    if (tokens.typography.scale) {
      for (const [name, size] of Object.entries(tokens.typography.scale)) {
        lines.push(`- ${name}: ${size}`)
      }
    }
  }
  if (tokens.spacing?.unit) {
    lines.push(`### Spacing`)
    lines.push(`- Base unit: ${tokens.spacing.unit}px`)
  }
  lines.push('')

  // Component constraints
  lines.push(`## Components`)
  for (const { name, selector, assertions } of results) {
    lines.push(`### ${name} (\`${selector}\`)`)
    for (const a of assertions) {
      lines.push(`- [${a.dimension}] ${a.description}`)
    }
    lines.push('')
  }

  return lines.join('\n')
}
